{
  "name": "DocuFlow Converter",
  "description": "Herramienta profesional para convertir PDFs a texto o Word con instrucciones personalizadas utilizando IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ConversionStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export enum OutputFormat {
  TXT = 'txt',
  DOC = 'doc', // We will generate HTML and save as .doc for Word compatibility
}

export interface FileQueueItem {
  id: string;
  file: File;
  status: ConversionStatus;
  resultContent?: string;
  errorMessage?: string;
  convertedName: string;
}

export interface ConversionSettings {
  format: OutputFormat;
  instructions: string;
}

import { OutputFormat } from '../types';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:application/pdf;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const downloadFile = (filename: string, content: string, format: OutputFormat) => {
  let mimeType = 'text/plain';
  let finalContent = content;

  if (format === OutputFormat.DOC) {
    mimeType = 'application/msword';
    // Wrap in basic HTML for Word to interpret it correctly
    finalContent = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><title>Document</title></head>
      <body>${content.replace(/\n/g, '<br>')}</body>
      </html>
    `;
  }

  const blob = new Blob([finalContent], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 9);
};

import { GoogleGenAI } from "@google/genai";
import { OutputFormat } from "../types";

// Initialize Gemini Client
// IMPORTANT: The API key is obtained exclusively from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const convertPdfContent = async (
  base64Data: string, 
  settings: { format: OutputFormat; instructions: string }
): Promise<string> => {

  const formatInstruction = settings.format === OutputFormat.DOC 
    ? "El formato de salida debe ser texto enriquecido (HTML básico sin CSS complejo) adecuado para ser guardado como un archivo .doc de Word." 
    : "El formato de salida debe ser texto plano (.txt).";

  const userInstruction = settings.instructions.trim() 
    ? `Instrucciones adicionales del usuario: ${settings.instructions}`
    : "Convierte el contenido del documento fielmente.";

  const prompt = `
    Actúa como un conversor de documentos profesional.
    Tu tarea es extraer y transformar el contenido del archivo PDF adjunto.

    ${formatInstruction}
    ${userInstruction}

    Si es texto plano, no uses markdown, solo texto.
    Si es para Word (HTML), usa etiquetas como <h1>, <p>, <b> para mantener la estructura.

    Devuelve SOLO el contenido convertido, sin explicaciones ni bloques de código de markdown (como \`\`\`html).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest', // Using 2.5 Flash as it is robust for multimodal document tasks
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    return response.text || "No se pudo generar contenido.";
  } catch (error) {
    console.error("Error converting PDF:", error);
    throw new Error("Falló la conversión con Gemini API.");
  }
};

import React from 'react';
import { ConversionSettings, OutputFormat } from '../types';

interface SettingsPanelProps {
  settings: ConversionSettings;
  setSettings: React.Dispatch<React.SetStateAction<ConversionSettings>>;
  disabled: boolean;
}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ settings, setSettings, disabled }) => {

  const handleFormatChange = (format: OutputFormat) => {
    setSettings(prev => ({ ...prev, format }));
  };

  const handleInstructionsChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setSettings(prev => ({ ...prev, instructions: e.target.value }));
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-6">
      <h2 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-indigo-600"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.1a2 2 0 0 1-1-1.72v-.51a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"/><circle cx="12" cy="12" r="3"/></svg>
        Configuración de Conversión
      </h2>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Format Selection */}
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-3">Formato de Salida</label>
          <div className="flex gap-4">
            <button
              onClick={() => handleFormatChange(OutputFormat.TXT)}
              disabled={disabled}
              className={`flex-1 flex flex-col items-center justify-center p-4 rounded-lg border-2 transition-all ${
                settings.format === OutputFormat.TXT
                  ? 'border-indigo-600 bg-indigo-50 text-indigo-700'
                  : 'border-slate-200 hover:border-slate-300 text-slate-500 hover:bg-slate-50'
              } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mb-2"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><line x1="10" y1="9" x2="8" y2="9"/></svg>
              <span className="font-semibold">Texto (.txt)</span>
            </button>

            <button
              onClick={() => handleFormatChange(OutputFormat.DOC)}
              disabled={disabled}
              className={`flex-1 flex flex-col items-center justify-center p-4 rounded-lg border-2 transition-all ${
                settings.format === OutputFormat.DOC
                  ? 'border-blue-600 bg-blue-50 text-blue-700'
                  : 'border-slate-200 hover:border-slate-300 text-slate-500 hover:bg-slate-50'
              } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="mb-2"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/><path d="M14 13H8"/><path d="M16 17H8"/><path d="M10 9H8"/></svg>
              <span className="font-semibold">Word (.doc)</span>
            </button>
          </div>
        </div>

        {/* Custom Instructions */}
        <div>
          <label htmlFor="instructions" className="block text-sm font-medium text-slate-700 mb-2">
            Instrucciones Personalizadas (Opcional)
          </label>
          <textarea
            id="instructions"
            value={settings.instructions}
            onChange={handleInstructionsChange}
            disabled={disabled}
            placeholder="Ej: Extrae solo las tablas, mantén el formato original, resume el contenido..."
            className="w-full h-[88px] p-3 rounded-lg border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 resize-none text-sm text-slate-700 placeholder:text-slate-400 disabled:bg-slate-50 disabled:text-slate-500"
          />
        </div>
      </div>
    </div>
  );
};

export default SettingsPanel;

import React, { useCallback, useState } from 'react';

interface DropZoneProps {
  onFilesAdded: (files: File[]) => void;
  disabled: boolean;
}

const DropZone: React.FC<DropZoneProps> = ({ onFilesAdded, disabled }) => {
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    if (disabled) return;
    setIsDragOver(true);
  }, [disabled]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    if (disabled) return;

    const files = Array.from(e.dataTransfer.files).filter(file => file.type === 'application/pdf');
    if (files.length > 0) {
      onFilesAdded(files);
    } else {
      alert("Por favor, sube solo archivos PDF.");
    }
  }, [onFilesAdded, disabled]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (disabled || !e.target.files) return;
    const files = Array.from(e.target.files).filter(file => file.type === 'application/pdf');
    onFilesAdded(files);
    // Reset value to allow uploading the same file again if needed
    e.target.value = '';
  }, [onFilesAdded, disabled]);

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`relative w-full border-2 border-dashed rounded-xl p-10 text-center transition-all duration-200 cursor-pointer group
        ${isDragOver 
          ? 'border-indigo-500 bg-indigo-50' 
          : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'
        }
        ${disabled ? 'opacity-50 pointer-events-none' : ''}
      `}
    >
      <input
        type="file"
        multiple
        accept=".pdf"
        onChange={handleFileInput}
        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
        disabled={disabled}
      />

      <div className="flex flex-col items-center justify-center space-y-4">
        <div className={`p-4 rounded-full bg-slate-100 group-hover:bg-white transition-colors`}>
          <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-indigo-600">
            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14 2z"/>
            <polyline points="14 2 14 8 20 8"/>
            <path d="M12 18v-6"/>
            <path d="M9 15l3-3 3 3"/>
          </svg>
        </div>
        <div className="text-slate-600">
          <span className="font-semibold text-indigo-600">Haz clic para subir</span> o arrastra tus archivos aquí
          <p className="text-sm text-slate-400 mt-1">Solo archivos PDF</p>
        </div>
      </div>
    </div>
  );
};

export default DropZone;

import React from 'react';
import { FileQueueItem, ConversionStatus, OutputFormat } from '../types';
import { downloadFile } from '../utils/fileHelpers';

interface QueueListProps {
  items: FileQueueItem[];
  onRemove: (id: string) => void;
  format: OutputFormat;
}

const QueueList: React.FC<QueueListProps> = ({ items, onRemove, format }) => {
  if (items.length === 0) return null;

  const getStatusBadge = (status: ConversionStatus) => {
    switch (status) {
      case ConversionStatus.PROCESSING:
        return (
          <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
            <svg className="animate-spin -ml-1 mr-1.5 h-3 w-3 text-blue-800" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
            Procesando
          </span>
        );
      case ConversionStatus.COMPLETED:
        return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">Completado</span>;
      case ConversionStatus.ERROR:
        return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-red-100 text-red-800">Error</span>;
      default:
        return <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">Pendiente</span>;
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden mt-6">
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-200">
        <h3 className="text-sm font-semibold text-slate-700 uppercase tracking-wider">Cola de Archivos ({items.length})</h3>
      </div>
      <ul className="divide-y divide-slate-200">
        {items.map((item) => (
          <li key={item.id} className="p-4 hover:bg-slate-50 transition-colors">
            <div className="flex items-center justify-between">
              <div className="flex items-center min-w-0 flex-1">
                <div className="flex-shrink-0">
                  <svg className="h-8 w-8 text-slate-400" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                  </svg>
                </div>
                <div className="ml-4 flex-1 min-w-0">
                  <div className="flex items-center justify-between mb-1">
                    <p className="text-sm font-medium text-slate-900 truncate">{item.file.name}</p>
                    <div className="ml-2 flex-shrink-0">
                        {getStatusBadge(item.status)}
                    </div>
                  </div>
                  <div className="flex items-center text-sm text-slate-500">
                    <span>{(item.file.size / 1024 / 1024).toFixed(2)} MB</span>
                  </div>
                  {item.status === ConversionStatus.ERROR && (
                      <p className="mt-1 text-xs text-red-600">{item.errorMessage}</p>
                  )}
                </div>
              </div>

              <div className="ml-6 flex items-center space-x-4">
                {item.status === ConversionStatus.COMPLETED && item.resultContent && (
                  <button
                    onClick={() => downloadFile(item.convertedName, item.resultContent!, format)}
                    className="text-indigo-600 hover:text-indigo-900 font-medium text-sm flex items-center"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Descargar
                  </button>
                )}

                {item.status === ConversionStatus.IDLE && (
                   <button
                   onClick={() => onRemove(item.id)}
                   className="text-slate-400 hover:text-red-600 transition-colors"
                   title="Eliminar"
                 >
                   <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                   </svg>
                 </button>
                )}

              </div>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default QueueList;

import React, { useState, useCallback } from 'react';
import DropZone from './components/DropZone';
import SettingsPanel from './components/SettingsPanel';
import QueueList from './components/QueueList';
import { FileQueueItem, ConversionStatus, OutputFormat, ConversionSettings } from './types';
import { generateId, fileToBase64 } from './utils/fileHelpers';
import { convertPdfContent } from './services/geminiService';

const App: React.FC = () => {
  const [queue, setQueue] = useState<FileQueueItem[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [settings, setSettings] = useState<ConversionSettings>({
    format: OutputFormat.TXT,
    instructions: '',
  });

  const handleFilesAdded = useCallback((files: File[]) => {
    const newItems: FileQueueItem[] = files.map(file => ({
      id: generateId(),
      file,
      status: ConversionStatus.IDLE,
      convertedName: file.name.replace('.pdf', `.${settings.format}`)
    }));
    setQueue(prev => [...prev, ...newItems]);
  }, [settings.format]);

  const handleRemoveItem = useCallback((id: string) => {
    setQueue(prev => prev.filter(item => item.id !== id));
  }, []);

  const processQueue = async () => {
    setIsProcessing(true);

    // We process sequentially to avoid hitting rate limits easily, 
    // although Promise.all could be used for parallel processing if limits allow.
    const itemsToProcess = queue.filter(item => item.status === ConversionStatus.IDLE);

    for (const item of itemsToProcess) {
      // Update status to processing
      setQueue(prev => prev.map(q => q.id === item.id ? { ...q, status: ConversionStatus.PROCESSING } : q));

      try {
        const base64 = await fileToBase64(item.file);

        // Ensure extension matches current settings at time of processing
        const extension = settings.format === OutputFormat.DOC ? 'doc' : 'txt';
        const convertedName = item.file.name.replace(/\.pdf$/i, `.${extension}`);

        const result = await convertPdfContent(base64, settings);

        setQueue(prev => prev.map(q => q.id === item.id ? {
          ...q,
          status: ConversionStatus.COMPLETED,
          resultContent: result,
          convertedName: convertedName
        } : q));

      } catch (error) {
        setQueue(prev => prev.map(q => q.id === item.id ? {
          ...q,
          status: ConversionStatus.ERROR,
          errorMessage: error instanceof Error ? error.message : "Error desconocido"
        } : q));
      }
    }

    setIsProcessing(false);
  };

  const pendingCount = queue.filter(item => item.status === ConversionStatus.IDLE).length;

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 text-white p-1.5 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"/><polyline points="14 2 14 8 20 8"/><path d="M16 13H8"/><path d="M16 17H8"/><path d="M10 9H8"/></svg>
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">DocuFlow</h1>
          </div>
          <div className="text-sm text-slate-500 font-medium">
            Powered by Gemini
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        <div className="mb-8 text-center sm:text-left">
          <h2 className="text-3xl font-bold text-slate-900 mb-2">Conversor de PDF con IA</h2>
          <p className="text-slate-600 max-w-2xl">
            Convierte tus documentos PDF a texto editable o Word manteniendo la estructura. 
            Personaliza el resultado con instrucciones naturales.
          </p>
        </div>

        {/* Settings Area */}
        <SettingsPanel 
          settings={settings} 
          setSettings={setSettings} 
          disabled={isProcessing} 
        />

        {/* Upload Area */}
        <DropZone onFilesAdded={handleFilesAdded} disabled={isProcessing} />

        {/* Action Button */}
        {pendingCount > 0 && (
          <div className="mt-6 flex justify-end animate-fade-in">
            <button
              onClick={processQueue}
              disabled={isProcessing}
              className={`
                flex items-center gap-2 px-6 py-3 rounded-lg text-white font-medium shadow-lg shadow-indigo-200 transition-all
                ${isProcessing 
                  ? 'bg-indigo-400 cursor-wait' 
                  : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-xl hover:-translate-y-0.5'
                }
              `}
            >
              {isProcessing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Procesando...
                </>
              ) : (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                  Convertir {pendingCount} Archivo{pendingCount !== 1 ? 's' : ''}
                </>
              )}
            </button>
          </div>
        )}

        {/* Queue / Results */}
        <QueueList 
          items={queue} 
          onRemove={handleRemoveItem} 
          format={settings.format}
        />
      </main>
    </div>
  );
};

export default App;

