export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = (error) => reject(error);
  });
};

export const downloadFile = (filename: string, content: string, format: OutputFormat) => {
  let mimeType = 'text/plain';
  let finalContent = content;

  if (format === OutputFormat.DOC) {
    mimeType = 'application/msword';
    // XML Header to force "Print Layout" (Diseño de Impresión) in MS Word
    const wordHeader = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' 
            xmlns:w='urn:schemas-microsoft-com:office:word' 
            xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <title>Document</title>
        <!--[if gte mso 9]>
        <xml>
          <w:WordDocument>
            <w:View>Print</w:View>
            <w:Zoom>100</w:Zoom>
            <w:DoNotOptimizeForBrowser/>
          </w:WordDocument>
        </xml>
        <![endif]-->
        <style>
          body { font-family: 'Calibri', 'Arial', sans-serif; font-size: 11pt; }
          p { margin: 0; padding: 0; }
          table { border-collapse: collapse; width: 100%; }
          td { border: 1px solid #ddd; padding: 8px; }
        </style>
      </head>
      <body>
    `;
    const wordFooter = `</body></html>`;

    // We assume content is pre-formatted HTML from pdfService
    finalContent = wordHeader + content + wordFooter;
  }

  const blob = new Blob([finalContent], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

export const generateId = (): string => {
  return Math.random().toString(36).substring(2, 9);
};

export const shareContent = async (platform: 'whatsapp' | 'telegram' | 'email', text: string, filename: string) => {
  // Note: Web Share API generally doesn't support sharing File objects to specific apps directly via URL schemes
  // We will share a message or the text content.

  const message = `Aquí tienes el archivo convertido: ${filename}`;
  const encodedMsg = encodeURIComponent(message);

  if (platform === 'whatsapp') {
    window.open(`https://wa.me/?text=${encodedMsg}`, '_blank');
  } else if (platform === 'telegram') {
    window.open(`https://t.me/share/url?url=${encodedMsg}&text=${encodedMsg}`, '_blank');
  } else if (platform === 'email') {
    window.open(`mailto:?subject=Archivo PDFluye: ${filename}&body=${encodedMsg}`, '_blank');
  }
};

import { OutputFormat } from '../types';

declare global {
  interface Window {
    pdfjsLib: any;
  }
}

interface TextItem {
  str: string;
  x: number;
  y: number;
  w: number;
  h: number;
  hasEOL: boolean;
}

export const convertPdfLocal = async (
  file: File, 
  settings: { format: OutputFormat }
): Promise<string> => {
  try {
    const arrayBuffer = await file.arrayBuffer();

    // Load the PDF file
    const loadingTask = window.pdfjsLib.getDocument({ data: arrayBuffer });
    const pdf = await loadingTask.promise;

    let fullOutput = '';

    // Iterate over all pages
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const viewport = page.getViewport({ scale: 1.5 }); // Higher scale for better coordinate precision
      const textContent = await page.getTextContent();

      const items: TextItem[] = textContent.items.map((item: any) => {
        // PDF coordinates: (0,0) is bottom-left. We convert to top-left for easier logic.
        const tx = item.transform;
        const x = tx[4];
        const y = viewport.height - tx[5]; // Flip Y
        return {
          str: item.str,
          x: x,
          y: y,
          w: item.width,
          h: item.height,
          hasEOL: item.hasEOL
        };
      });

      // Sort items: First by Y (top to bottom), then by X (left to right)
      // Allow a small error margin for Y to group items on the "same line"
      items.sort((a, b) => {
        if (Math.abs(a.y - b.y) < 5) {
          return a.x - b.x;
        }
        return a.y - b.y;
      });

      let pageHtml = '';
      let pageText = '';
      let lastY = -1;
      let lastX = -1;

      // Simple heuristic to reconstruct layout
      items.forEach((item) => {
        if (lastY !== -1 && Math.abs(item.y - lastY) > 8) {
          // New Line
          if (settings.format === OutputFormat.DOC) {
            pageHtml += '<br>'; 
          } else {
            pageText += '\n';
          }
          lastX = -1; 
        }

        // Detect large gaps (simulating tabs/columns)
        if (lastX !== -1 && (item.x - lastX) > 20) {
           if (settings.format === OutputFormat.DOC) {
             // Use non-breaking spaces or a span with margin for DOC visual fidelity
             pageHtml += '&nbsp;&nbsp;&nbsp;&nbsp;'; 
           } else {
             pageText += '\t';
           }
        } else if (lastX !== -1) {
           // Small gap, just a space
           if (settings.format === OutputFormat.DOC) pageHtml += ' ';
           else pageText += ' ';
        }

        if (settings.format === OutputFormat.DOC) {
           pageHtml += item.str;
        } else {
           pageText += item.str;
        }

        lastY = item.y;
        lastX = item.x + item.w;
      });

      if (settings.format === OutputFormat.DOC) {
        // Wrap page content in a div to simulate a page break if needed later
        fullOutput += `<div style="page-break-after: always; margin-bottom: 2rem;">${pageHtml}</div>`;
      } else {
        fullOutput += pageText + '\n\n-------------------\n\n';
      }
    }

    return fullOutput;

  } catch (error) {
    console.error("Error converting PDF locally:", error);
    throw new Error("No se pudo leer el archivo PDF. Asegúrate de que no esté corrupto o protegido con contraseña.");
  }
};

