    const itemsToProcess = queue.filter(item => item.status === ConversionStatus.IDLE);

    for (const item of itemsToProcess) {
      setQueue(prev => prev.map(q => q.id === item.id ? { ...q, status: ConversionStatus.PROCESSING } : q));

