export default App;

export enum ConversionStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export enum OutputFormat {
  TXT = 'txt',
  DOC = 'docx', 
  XLS = 'xlsx',
  PPT = 'pptx'
}

export type Language = 'es' | 'en' | 'pt';
export type StorageLocation = 'local' | 'drive';

export interface FileQueueItem {
  id: string;
  file: File;
  status: ConversionStatus;
  resultContent?: any; // Can be string, Blob, or Buffer depending on library
  errorMessage?: string;
  convertedName: string;
  timestamp: number;
}

export interface ConversionSettings {
  format: OutputFormat;
}

export interface GlobalSettings {
  language: Language;
  destination: StorageLocation;
}

// Global declaration for File System Access API
declare global {
  interface Window {
    showDirectoryPicker(): Promise<FileSystemDirectoryHandle>;
  }
  interface FileSystemDirectoryHandle {
    getFileHandle(name: string, options?: { create: boolean }): Promise<FileSystemFileHandle>;
  }
  interface FileSystemFileHandle {
    createWritable(): Promise<FileSystemWritableFileStream>;
  }
  interface FileSystemWritableFileStream {
    write(data: any): Promise<void>;
    close(): Promise<void>;
  }
}

import React, { useCallback, useState } from 'react';

interface DropZoneProps {
  onFilesAdded: (files: File[]) => void;
  disabled: boolean;
  texts: {
    clickToUpload: string;
    orDrag: string;
    onlyPdf: string;
    alertPdf: string;
  };
}

const DropZone: React.FC<DropZoneProps> = ({ onFilesAdded, disabled, texts }) => {
  const [isDragOver, setIsDragOver] = useState(false);

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    if (disabled) return;
    setIsDragOver(true);
  }, [disabled]);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
    if (disabled) return;

    const files = Array.from(e.dataTransfer.files).filter((file: File) => file.type === 'application/pdf');
    if (files.length > 0) {
      onFilesAdded(files);
    } else {
      alert(texts.alertPdf);
    }
  }, [onFilesAdded, disabled, texts]);

  const handleFileInput = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (disabled || !e.target.files) return;
    const files = Array.from(e.target.files).filter((file: File) => file.type === 'application/pdf');
    onFilesAdded(files);
    e.target.value = '';
  }, [onFilesAdded, disabled]);

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`relative w-full border-2 border-dashed rounded-xl p-10 text-center transition-all duration-200 cursor-pointer group
        ${isDragOver 
          ? 'border-yellow-400 bg-yellow-400/5' 
          : 'border-zinc-700 hover:border-yellow-400/50 hover:bg-zinc-900'
        }
        ${disabled ? 'opacity-50 pointer-events-none' : ''}
      `}
    >
      <input
        type="file"
        multiple
        accept=".pdf"
        onChange={handleFileInput}
        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer disabled:cursor-not-allowed"
        disabled={disabled}
      />

      <div className="flex flex-col items-center justify-center space-y-4">
        <div className={`p-4 rounded-full bg-zinc-800 group-hover:bg-zinc-700 transition-colors`}>
          <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-yellow-400">
            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14 2z"/>
            <polyline points="14 2 14 8 20 8"/>
            <path d="M12 18v-6"/>
            <path d="M9 15l3-3 3 3"/>
          </svg>
        </div>
        <div className="text-zinc-400">
          <span className="font-bold text-yellow-400">{texts.clickToUpload}</span> {texts.orDrag}
          <p className="text-sm text-zinc-600 mt-1">{texts.onlyPdf}</p>
        </div>
      </div>
    </div>
  );
};

export default DropZone;

import React from 'react';
import { ConversionSettings, OutputFormat } from '../types';

interface SettingsPanelProps {
  settings: ConversionSettings;
  setSettings: React.Dispatch<React.SetStateAction<ConversionSettings>>;
  disabled: boolean;
  texts: {
    title: string;
    format: string;
    formats: {
      txt: string;
      doc: string;
      xls: string;
      ppt: string;
    }
