}

const SettingsPanel: React.FC<SettingsPanelProps> = ({ settings, setSettings, disabled, texts }) => {

  const handleFormatChange = (format: OutputFormat) => {
    setSettings(prev => ({ ...prev, format }));
  };

  const FormatButton = ({ format, label, icon }: { format: OutputFormat, label: string, icon: React.ReactNode }) => (
