              <div className="flex items-center min-w-0 flex-1">
                <div className="flex-shrink-0">
                  <svg className="h-10 w-10 text-zinc-600" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                </div>
                <div className="ml-4 flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <p className="text-sm font-bold text-zinc-200 truncate max-w-[200px]">{item.file.name}</p>
                    <span className="text-zinc-500 text-xs">→</span>
                    <p className="text-sm font-medium text-yellow-400 truncate max-w-[200px]">{item.convertedName}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    {getStatusBadge(item.status)}
                    <span className="text-xs text-zinc-500">{(item.file.size / 1024 / 1024).toFixed(2)} MB</span>
                  </div>
                  {item.status === ConversionStatus.ERROR && (
                      <p className="mt-1 text-xs text-red-400">{item.errorMessage}</p>
                  )}
                </div>
              </div>

              {/* Actions: Download & Delete */}
              <div className="flex items-center gap-2 self-end sm:self-center">

                {item.status === ConversionStatus.COMPLETED && (
                    <button
                        onClick={() => downloadFile(item.convertedName, item.resultContent!, format)}
                        className="p-2 rounded-lg bg-yellow-400 text-black hover:bg-yellow-300 transition-all font-bold text-xs flex items-center gap-1"
                        title={texts.download}
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
                        {texts.download}
                    </button>
                )}

                {/* Delete */}
                <button
                   onClick={() => onRemove(item.id)}
                   className="p-2 rounded-lg bg-zinc-800 text-zinc-500 hover:text-red-400 hover:bg-zinc-700 transition-all"
                   title={texts.delete}
                 >
                   <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/><line x1="10" y1="11" x2="10" y2="17"/><line x1="14" y1="11" x2="14" y2="17"/></svg>
                 </button>
              </div>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default QueueList;

export enum ConversionStatus {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR',
}

export enum OutputFormat {
  TXT = 'txt',
  DOC = 'doc',
  XLS = 'xls',
  PPT = 'ppt'
}

export interface FileQueueItem {
  id: string;
  file: File;
  status: ConversionStatus;
  resultContent?: string;
  errorMessage?: string;
  convertedName: string;
  timestamp: number;
}

export interface ConversionSettings {
  format: OutputFormat;
  instructions: string;
}

// Global declaration for File System Access API (Optional support kept in types but simplified usage)
declare global {
  interface Window {
    showDirectoryPicker(): Promise<FileSystemDirectoryHandle>;
  }
  interface FileSystemDirectoryHandle {
    getFileHandle(name: string, options?: { create: boolean }): Promise<FileSystemFileHandle>;
  }
  interface FileSystemFileHandle {
    createWritable(): Promise<FileSystemWritableFileStream>;
  }
  interface FileSystemWritableFileStream {
    write(data: any): Promise<void>;
    close(): Promise<void>;
  }
}

import { GoogleGenAI } from "@google/genai";
import { OutputFormat, ConversionSettings } from "../types";

// Initialize Gemini Client
// IMPORTANT: The API key is obtained exclusively from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const convertPdfContent = async (
  base64Data: string, 
  settings: ConversionSettings
): Promise<string> => {

  const formatInstruction = settings.format === OutputFormat.DOC 
    ? "El formato de salida debe ser texto enriquecido (HTML básico sin CSS complejo) adecuado para ser guardado como un archivo .doc de Word." 
    : "El formato de salida debe ser texto plano (.txt).";

  const userInstruction = settings.instructions.trim() 
    ? `Instrucciones adicionales del usuario: ${settings.instructions}`
    : "Convierte el contenido del documento fielmente.";

  const prompt = `
    Actúa como un conversor de documentos profesional.
    Tu tarea es extraer y transformar el contenido del archivo PDF adjunto.

    ${formatInstruction}
    ${userInstruction}

    Si es texto plano, no uses markdown, solo texto.
    Si es para Word (HTML), usa etiquetas como <h1>, <p>, <b> para mantener la estructura.

    Devuelve SOLO el contenido convertido, sin explicaciones ni bloques de código de markdown (como \`\`\`html).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // Using Gemini 3 Flash as it is robust for multimodal document tasks
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'application/pdf',
              data: base64Data
            }
          },
          {
            text: prompt
          }
        ]
      }
    });

    return response.text || "No se pudo generar contenido.";
  } catch (error) {
    console.error("Error converting PDF:", error);
    throw new Error("Falló la conversión con Gemini API.");
  }
};
